import{_ as a,c as t,o as n,az as o}from"./chunks/framework.OpiqYVxT.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/intro.md","filePath":"en/guide/intro.md","lastUpdated":1777332424000}'),i={name:"en/guide/intro.md"};function l(r,e,s,p,c,d){return n(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>NekoBot is an <strong>event-driven chatbot framework</strong> built with Python.</p><h2 id="what-is-nekobot" tabindex="-1">What is NekoBot <a class="header-anchor" href="#what-is-nekobot" aria-label="Permalink to &quot;What is NekoBot&quot;">​</a></h2><p>NekoBot is a multi-platform intelligent chatbot framework designed to simplify the development, deployment, and management of chatbots. It adopts an event-driven asynchronous architecture, supports plugin extensions, and integrates multiple LLM service providers.</p><h3 id="design-philosophy" tabindex="-1">Design Philosophy <a class="header-anchor" href="#design-philosophy" aria-label="Permalink to &quot;Design Philosophy&quot;">​</a></h3><ul><li><strong>Event-driven</strong>: Asynchronous event processing for high-performance message response</li><li><strong>Modular</strong>: Plugin-based design for easy extension and maintenance</li><li><strong>Fully decoupled</strong>: Components communicate through clear interfaces, with platforms, plugins, and providers independent of each other</li><li><strong>Cross-platform</strong>: Support for multiple chat platform integrations</li><li><strong>AI-native</strong>: Deep integration with large language models and AI tools</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>NekoBot uses a layered architecture design:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                Web UI (Quart)               │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│          NekoBotFramework (Core)            │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  ┌─────────────┐ ┌─────────────┐ ┌─────────┐│</span></span>
<span class="line"><span>│  │   Plugins   │ │  Providers  │ │  Tools  ││</span></span>
<span class="line"><span>│  └─────────────┘ └─────────────┘ └─────────┘│</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  ┌─────────────┐ ┌─────────────┐ ┌─────────┐│</span></span>
<span class="line"><span>│  │  Platforms  │ │  Runtime    │ │  MCP    ││</span></span>
<span class="line"><span>│  └─────────────┘ └─────────────┘ └─────────┘│</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="core-components" tabindex="-1">Core Components <a class="header-anchor" href="#core-components" aria-label="Permalink to &quot;Core Components&quot;">​</a></h3><ol><li><strong>NekoBotFramework</strong>: Main framework class coordinating all subsystems</li><li><strong>Platforms</strong>: Platform adapters (currently supports OneBot V11/QQ)</li><li><strong>Providers</strong>: LLM service provider integration (OpenAI, Anthropic, Gemini, etc.)</li><li><strong>Plugins</strong>: Plugin system with hot-reload support</li><li><strong>Runtime</strong>: Runtime registry and event dispatching</li><li><strong>Tools</strong>: Tool registry with MCP protocol support</li><li><strong>Web UI</strong>: Management interface based on Quart</li></ol><h3 id="fully-decoupled-architecture" tabindex="-1">Fully Decoupled Architecture <a class="header-anchor" href="#fully-decoupled-architecture" aria-label="Permalink to &quot;Fully Decoupled Architecture&quot;">​</a></h3><p>NekoBot adopts a <strong>fully decoupled</strong> design philosophy where components communicate through clear interfaces and remain independent:</p><ul><li><strong>Platform Agnostic</strong>: Platform adapters (<code>Platforms</code>) are decoupled from the core framework, communicating through the <code>PlatformEvent</code> interface</li><li><strong>Plugin Independence</strong>: Plugins (<code>Plugins</code>) register commands and event handlers via decorators without direct dependency on framework implementation</li><li><strong>Provider Abstraction</strong>: LLM providers (<code>Providers</code>) implement a unified <code>Provider</code> interface, allowing seamless switching</li><li><strong>Tool Decoupling</strong>: AI tools (<code>Tools</code>) are separated from execution logic, registered via MCP protocol or locally</li><li><strong>Configuration Isolation</strong>: Configuration system uses JSON Schema validation with isolated component configurations</li><li><strong>Event Bus</strong>: All communication flows through an event bus, eliminating direct dependencies between components</li></ul><p>This design enables:</p><ul><li>Platform adapters to be developed and replaced independently</li><li>Plugins to be hot-loaded/unloaded without affecting other components</li><li>LLM providers to be switched on-demand (e.g., from OpenAI to Claude)</li><li>Tools to be dynamically registered and unregistered</li><li>Easy testing and maintenance of the system</li></ul><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h2><h3 id="event-driven-architecture" tabindex="-1">Event-Driven Architecture <a class="header-anchor" href="#event-driven-architecture" aria-label="Permalink to &quot;Event-Driven Architecture&quot;">​</a></h3><ul><li><code>PlatformEvent</code>-based event model</li><li>Asynchronous message processing and dispatching</li><li>Extensible event handler chain</li></ul><h3 id="plugin-system" tabindex="-1">Plugin System <a class="header-anchor" href="#plugin-system" aria-label="Permalink to &quot;Plugin System&quot;">​</a></h3><ul><li>Dynamic plugin loading/unloading</li><li>Hot-reload support without restart</li><li>Plugin communication and dependency management</li></ul><h3 id="llm-integration" tabindex="-1">LLM Integration <a class="header-anchor" href="#llm-integration" aria-label="Permalink to &quot;LLM Integration&quot;">​</a></h3><ul><li>Support for OpenAI, Anthropic, Google Gemini</li><li>Support for OpenAI-compatible APIs (DeepSeek, Ollama, etc.)</li><li>Text-to-speech (TTS) and speech-to-text (STT)</li><li>Unified Provider API interface</li></ul><h3 id="platform-support" tabindex="-1">Platform Support <a class="header-anchor" href="#platform-support" aria-label="Permalink to &quot;Platform Support&quot;">​</a></h3><ul><li><strong>OneBot V11 (QQ)</strong>: Complete QQ bot support</li><li>Supports WebSocket reverse connection and HTTP protocol</li></ul><h3 id="web-management-interface" tabindex="-1">Web Management Interface <a class="header-anchor" href="#web-management-interface" aria-label="Permalink to &quot;Web Management Interface&quot;">​</a></h3><ul><li>Built with Quart (async Flask)</li><li>Visual configuration management</li><li>Plugin management and log viewing</li><li>Real-time status monitoring</li></ul><h3 id="mcp-support" tabindex="-1">MCP Support <a class="header-anchor" href="#mcp-support" aria-label="Permalink to &quot;MCP Support&quot;">​</a></h3><ul><li>Native Model Context Protocol support</li><li>AI tool integration and management</li><li>Skill management system</li></ul><h3 id="permission-system" tabindex="-1">Permission System <a class="header-anchor" href="#permission-system" aria-label="Permalink to &quot;Permission System&quot;">​</a></h3><ul><li>Role-based permission control</li><li>Fine-grained permission management</li><li>Multi-level permissions (user, group, global)</li></ul><h3 id="conversation-management" tabindex="-1">Conversation Management <a class="header-anchor" href="#conversation-management" aria-label="Permalink to &quot;Conversation Management&quot;">​</a></h3><ul><li>SQLite conversation storage</li><li>Dialogue context management</li><li>Automatic summarization and persistence</li></ul><h2 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology Stack&quot;">​</a></h2><ul><li><strong>Backend</strong>: Python 3.11+, Quart, SQLite, loguru</li><li><strong>Frontend</strong>: React 19, TypeScript, Vite, Material-UI (in development)</li><li><strong>Communication</strong>: WebSocket, HTTP, MCP protocol</li><li><strong>Database</strong>: SQLite (conversation storage)</li><li><strong>Deployment</strong>: Docker support</li></ul><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User Message → Platform Adapter → PlatformEvent</span></span>
<span class="line"><span>    → BaseDispatcher → Event Dispatching</span></span>
<span class="line"><span>    → Command Handler / Event Handler</span></span>
<span class="line"><span>    → LLM Provider → Response Generation</span></span>
<span class="line"><span>    → Platform Adapter → User Reply</span></span></code></pre></div><h2 id="use-cases" tabindex="-1">Use Cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use Cases&quot;">​</a></h2><h3 id="qq-group-chatbot" tabindex="-1">QQ Group Chatbot <a class="header-anchor" href="#qq-group-chatbot" aria-label="Permalink to &quot;QQ Group Chatbot&quot;">​</a></h3><ul><li>Intelligent Q&amp;A and conversation</li><li>Group management and automation</li><li>Entertainment and gaming features</li></ul><h3 id="ai-conversation-assistant" tabindex="-1">AI Conversation Assistant <a class="header-anchor" href="#ai-conversation-assistant" aria-label="Permalink to &quot;AI Conversation Assistant&quot;">​</a></h3><ul><li>Personal intelligent assistant</li><li>Customer service and consulting bot</li><li>Education and tutoring system</li></ul><h3 id="enterprise-applications" tabindex="-1">Enterprise Applications <a class="header-anchor" href="#enterprise-applications" aria-label="Permalink to &quot;Enterprise Applications&quot;">​</a></h3><ul><li>Internal work assistant</li><li>Automated workflows</li><li>Data query and reporting</li></ul><h3 id="development-platform" tabindex="-1">Development Platform <a class="header-anchor" href="#development-platform" aria-label="Permalink to &quot;Development Platform&quot;">​</a></h3><ul><li>Rapid bot application development</li><li>AI feature integration platform</li><li>Plugin ecosystem building</li></ul><h2 id="project-status" tabindex="-1">Project Status <a class="header-anchor" href="#project-status" aria-label="Permalink to &quot;Project Status&quot;">​</a></h2><p>NekoBot is currently in <strong>active development</strong> with stable core functionality.</p><h3 id="completed-features" tabindex="-1">Completed Features <a class="header-anchor" href="#completed-features" aria-label="Permalink to &quot;Completed Features&quot;">​</a></h3><ul><li>Core framework and event-driven architecture</li><li>Complete OneBot V11 platform support</li><li>Multiple LLM provider integration</li><li>Plugin system with hot-reload</li><li>Basic Web management interface</li><li>MCP protocol support</li><li>Permission and conversation management</li></ul><h3 id="features-in-development" tabindex="-1">Features in Development <a class="header-anchor" href="#features-in-development" aria-label="Permalink to &quot;Features in Development&quot;">​</a></h3><ul><li>Additional platform adapters (when developed)</li><li>Plugin marketplace and online installation</li><li>Advanced knowledge base features</li><li>Frontend Dashboard improvements</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./getting-started.html">Quick Start</a> - Start using NekoBot now</li><li>Check <a href="https://github.com/OfficialNekoTeam/NekoBot" target="_blank" rel="noreferrer">GitHub Project</a> for latest code</li><li><a href="./plugin-development.html">Plugin Development</a> - Learn how to develop NekoBot plugins</li></ul>`,54)])])}const m=a(i,[["render",l]]);export{h as __pageData,m as default};
